INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('56f0be04-0f11-5069-ab92-07d25eda9ee3', 'd99f5952-91d8-41d5-8a1c-267609e39a20', 'The trip to the museum takes ___ thirty minutes.', '去博物館的行程大約需要三十分鐘。', 'about', 'exactly', 'highly', 'suddenly', '表示數量或時間的近似值 (大約)', 'about + [數字] → 大約的數量', '2026-07-05 07:40:09', '2026-07-05 07:40:09'),
('85ea8b11-6cd6-5ced-ade0-c57c4c17bbc3', '024268af-3dee-4985-8a24-5cffac621c55', 'To many people, the customs of this remote tribe seem quite ___ and difficult to understand.', '對許多人來說，這個偏遠部落的習俗似乎相當陌生且難以理解。', 'alien', 'familiar', 'common', 'natural', 'alien 源自拉丁語 alienus，意為屬於他人的或外來的。', 'alien (外星人/外來的) → 想像外星人從太空降落，對我們來說他是外來的且陌生的。', '2026-07-06 19:47:39', '2026-07-06 19:47:39'),
('38df3978-9849-5993-abc6-94ed420095cf', 'f56e726d-1d9f-4ca7-a30e-daba888b6823', 'Due to its lightweight properties and resistance to rust, ___ is a popular material for making aircraft components and beverage containers.', '由於其輕量特性與抗鏽能力，鋁是製造飛機零件和飲料容器的常用材料。', 'aluminum', 'copper', 'iron', 'silver', '源自拉丁語 alumen，原指一種化學物質，後來用來命名這種輕質金屬。', '聯想：鋁 (aluminum) 很輕，可以用來做 almost (幾乎) 所有輕便的罐裝飲料。', '2026-07-06 20:26:19', '2026-07-06 20:26:19'),
('59be4d83-5035-5dba-9c57-ac1000414a9f', '21c20259-3de9-4c2d-a48b-5eeb3fa6e3d2', 'Is there ___ I can do to help you with your project?', '有什麼我可以幫你完成專案的事嗎？', 'anything', 'someone', 'everyone', 'nobody', 'any (任何) + thing (事物)', 'any (任何) + thing (事物) → 任何事物', '2026-07-06 22:29:26', '2026-07-06 22:29:26'),
('2afd5f64-eb1b-548e-9a90-5d882c0179cf', '10aa060b-bf36-48cc-afef-df6959936c7d', 'The librarian spent the entire afternoon trying to ___ the books in alphabetical order.', '圖書館管理員花了一整個下午試圖將書籍按字母順序排列。', 'arrange', 'purchase', 'describe', 'collect', 'ar- (朝向) + range (排列/序列) → 整理、排列。', '想像在整理書架時，要把書按順序 arrange (排列) 好。', '2026-07-07 00:07:54', '2026-07-07 00:07:54'),
('a26d124a-57c4-5a26-b9cc-746b41d1372b', '880efc21-cf4a-47c4-a316-9716340133c2', 'In the sentence ''She can swim'', the word ''can'' is a(n) ___.', '在「She can swim」這個句子中，「can」是一個助動詞。', 'auxiliary', 'conjunction', 'preposition', 'adverb', '字根 aux- 來自拉丁語 auxilium，意思是 help (幫助)。', '可以聯想音響上的 AUX 介面，它是用來「輔助」音訊輸入的工具。', '2026-07-07 03:57:55', '2026-07-07 03:57:55'),
('b748978d-3ce9-5b63-8411-95ae74fba1a3', '6af5d97c-e8af-4cb2-815a-f99f95a1317c', 'The temperature is ___ zero degrees today.', '今天的溫度在零度以下。', 'below', 'between', 'among', 'against', 'be (在) + low (低) → 在低處 → 在...之下', 'low 代表低，below 就是在低的位置。', '2026-07-07 03:25:55', '2026-07-07 03:25:55'),
('a04adbbd-c768-5d13-abdf-e272a24905bb', 'fae37cff-858e-40cb-9fed-8c6f4676b680', 'Be careful with that glass! You might ___ it.', '小心那個玻璃杯！你可能會打破它。', 'break', 'wash', 'carry', 'bring', 'break 當動詞時，表示「打破」或「弄壞」。', 'break 聽起來像「不開」，東西壞了就不能開了。', '2026-07-07 08:16:17', '2026-07-07 08:16:17'),
('5ba510e3-3720-52d8-a54f-54d05804b037', 'cc78a13a-b0f7-4a94-9146-d1a114090d5a', 'If you want to improve, you need to put more ___ into your practice.', '如果你想要進步，你需要在練習中投入更多努力。', 'effort', 'luck', 'money', 'music', 'effort 由 ex (向外) 與 fort (力量) 組成，表示把力量使出來。', 'effort → e (out) + fort (strength) → 拿出力量 → 努力', '2026-07-07 03:19:06', '2026-07-07 03:19:06'),
('f9770b48-c424-57fe-9ca4-53ed79d3dc2f', '3c5b3e5a-5d9f-46d9-baf1-a858d8425fd5', 'I have two pens. You can take ___.', '我有兩枝筆。你可以拿一支。', 'one', 'some', 'any', 'each', '在此作為代名詞，用來代替前面提過的名詞 (pens)。', '用 one 來代替重複出現的名詞。', '2026-07-06 10:37:04', '2026-07-06 10:37:04'),
('af3590fd-778a-55e3-b642-5a3a3a8fef8f', '1d86e27e-0866-4c5e-8277-4bc91cc8ab5e', 'Is ___ the reason why you were so angry this morning?', '那就是你今天早上為什麼這麼生氣的原因嗎？', 'that', 'what', 'which', 'who', '代名詞 (pron.)，用來指代前面提到或已知的事物。', 'That (那件事) → 指代已知的事。', '2026-07-05 14:26:52', '2026-07-05 14:26:52'),
('1c79c445-9a96-532b-908d-3824d5f38f67', 'bdf62229-5b97-4ca6-b357-8e0d6aac7c03', 'I will give ___ the instructions so that you can start the task immediately.', '我會給你指示，這樣你就能立即開始這項任務。', 'you', 'him', 'her', 'them', 'you 為代名詞，在此作為受格使用。', 'you 就是你，對著對方說話時必備。', '2026-07-05 10:33:21', '2026-07-05 10:33:21');
